thod\": null, \"frequencyPenaltyEnabled\": false, \"frequency_penalty\": 0.3, \"llm_id\": \"deepseek-chat@DeepSeek\", \"maxTokensEnabled\": false, \"max_retries\": 3, \"max_rounds\": 5, \"max_tokens\": 4096, \"mcp\": [], \"message_history_window_size\": 12, \"outputs\": {\"content\": {\"type\": \"string\", \"value\": \"\"}}, \"parameter\": \"Balance\", \"presencePenaltyEnabled\": false, \"presence_penalty\": 0.2, \"prompts\": [{\"content\": \"The user query is {sys.query}\", \"role\": \"user\"}], \"sys_prompt\": \"You are an empathetic mood-soothing assistant.  \\n\\nYour role is to comfort and encourage users when they feel upset or frustrated.  \\n\\n- Use a warm, kind, and understanding tone.  \\n\\n- Focus on showing empathy and emotional support rather than solving the problem directly.  \\n\\n- Always encourage users with positive and reassuring statements.  \", \"temperature\": 0.5, \"temperatureEnabled\": true, \"tools\": [], \"topPEnabled\": false, \"top_p\": 0.85, \"user_prompt\": \"\", \"visual_files_var\": \"\"}, \"label\": \"Agent\", \"name\": \"Soothe mood\"}, \"dragging\": false, \"id\": \"Agent:DullTownsHope\", \"measured\": {\"height\": 84, \"width\": 200}, \"position\": {\"x\": 722.665715093248, \"y\": 281.3422183879642}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"agentNode\"}, {\"data\": {\"form\": {\"cross_languages\": [], \"empty_response\": \"\", \"kb_ids\": [], \"keywords_similarity_weight\": 0.7, \"outputs\": {\"formalized_content\": {\"type\": \"string\", \"value\": \"\"}}, \"query\": \"sys.query\", \"rerank_id\": \"\", \"similarity_threshold\": 0.2, \"top_k\": 1024, \"top_n\": 8, \"use_kg\": false}, \"label\": \"Retrieval\", \"name\": \"Search product info\"}, \"dragging\": false, \"id\": \"Retrieval:ShyPumasJoke\", \"measured\": {\"height\": 50, \"width\": 200}, \"position\": {\"x\": 645.6873721057459, \"y\": 516.6923702571407}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"retrievalNode\"}, {\"data\": {\"form\": {\"delay_after_error\": 1, \"description\": \"\", \"exception_comment\": \"\", \"exception_default_value\": \"\", \"exception_goto\": [], \"exception_method\": null, \"frequencyPenaltyEnabled\": false, \"frequency_penalty\": 0.7, \"llm_id\": \"deepseek-chat@DeepSeek\", \"maxTokensEnabled\": false, \"max_retries\": 3, \"max_rounds\": 5, \"max_tokens\": 256, \"mcp\": [], \"message_history_window_size\": 12, \"outputs\": {\"content\": {\"type\": \"string\", \"value\": \"\"}}, \"presencePenaltyEnabled\": false, \"presence_penalty\": 0.4, \"prompts\": [{\"content\": \"The user query is {sys.query}\\n\\nThe relevant document are {Retrieval:ShyPumasJoke@formalized_content}\", \"role\": \"user\"}], \"sys_prompt\": \"You are a highly professional product information advisor.  \\n\\nYour only mission is to provide accurate, factual, and structured answers to all product-related queries.\\n\\nAbsolutely no assumptions, guesses, or fabricated content are allowed. \\n\\n**Key Principles:**\\n\\n1. **Strict Database Reliance:**  \\n\\n   - Every answer must be based solely on the verified product information stored in the relevant documen.\\n\\n   - You are NOT allowed to invent, speculate, or infer details beyond what is retrieved.  \\n\\n   - If you cannot find relevant data, respond with: *\\\"I cannot find this information in our official product database. Please check back later or provide more details for further search.\\\"*\\n\\n2. **Information Accuracy and Structure:**  \\n\\n   - Provide information in a clear, concise, and professional way.  \\n\\n   - Use bullet points or numbered lists if there are multiple key points (e.g., features, price, warranty, technical specifications).  \\n\\n   - Always specify the version or model number when applicable to avoid confusion.\\n\\n3. **Tone and Style:**  \\n\\n   - Maintain a polite, professional, and helpful tone at all times.  \\n\\n   - Avoid marketing exaggeration or promotional language; stay strictly factual.  \\n\\n   - Do not express personal opinions; only cite official product data.\\n\\n4.  **User Guidance:**  \\n\\n   - If the user\\u2019s query is unclear or too broad, politely request clarification or guide them to provide more specific product details (e.g., product name, model, version).  \\n\\n   - Example: *\\\"Could you please specify the product model or category so I can retrieve the most relevant information for you?\\\"*\\n\\n5. **Response Length and Formatting:**  \\n\\n   - Keep each answer within 100\\u2013150 words for general queries.  \\n\\n   - For complex or multi-step explanations, you may extend to 200\\u2013250 words, but always remain clear and well-structured.\\n\\n6. **Critical Reminder:**  \\n\\nYour authority and reliability depend entirely on the relevant document responses. Any fabricated, speculative, or unverified content will be considered a critical failure of your role.\\n\\n\\n\", \"temperature\": 0.1, \"temperatureEnabled\": true, \"tools\": [], \"topPEnabled\": false, \"top_p\": 0.3, \"user_prompt\": \"\", \"visual_files_var\": \"\"}, \"label\": \"Agent\", \"name\": \"Product info\"}, \"dragging\": false, \"id\": \"Agent:KhakiSunsJudge\", \"measured\": {\"height\": 84, \"width\": 200}, \"position\": {\"x\": 726.580040161058, \"y\": 386.5448208363979}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"agentNode\"}, {\"data\": {\"form\": {\"text\": \"This is an intelligent customer service processing system workflow based on user intent classification. It uses LLM to identify user demand types and transfers them to the corresponding professional agent for processing.\"}, \"label\": \"Note\", \"name\": \"Workflow Overall Description\"}, \"dragHandle\": \".note-drag-handle\", \"dragging\": false, \"height\": 171, \"id\": \"Note:AllGuestsShow\", \"measured\": {\"height\": 171, \"width\": 380}, \"position\": {\"x\": -283.6407251474677, \"y\": 157.2943019466498}, \"resizing\": false, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"noteNode\", \"width\": 380}, {\"data\": {\"form\": {\"text\": \"Here, product document snippets related to the user\'s question will be retrieved from the knowledge base first, and the relevant document snippets will be passed to the LLM together with the user\'s question.\"}, \"label\": \"Note\", \"name\": \"Product info Agent\"}, \"dragHandle\": \".note-drag-handle\", \"dragging\": false, \"height\": 154, \"id\": \"Note:IcyBooksCough\", \"measured\": {\"height\": 154, \"width\": 370}, \"position\": {\"x\": 1014.0959071234828, \"y\": 492.830874176321}, \"resizing\": false, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"noteNode\", \"width\": 370}, {\"data\": {\"form\": {\"text\": \"Here, a text will be randomly selected for answering\"}, \"label\": \"Note\", \"name\": \"What else\\uff1f\"}, \"dragHandle\": \".note-drag-handle\", \"dragging\": false, \"id\": \"Note:AllThingsHide\", \"measured\": {\"height\": 136, \"width\": 249}, \"position\": {\"x\": 770.7060131788647, \"y\": -123.23496705283817}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"noteNode\"}, {\"data\": {\"form\": {\"groups\": [{\"group_name\": \"LLM_Response\", \"type\": \"string\", \"variables\": [{\"value\": \"Agent:TwelveOwlsWatch@content\"}, {\"value\": \"Agent:DullTownsHope@content\"}, {\"value\": \"Agent:KhakiSunsJudge@content\"}]}], \"outputs\": {\"LLM_Response\": {\"type\": \"string\"}}}, \"label\": \"VariableAggregator\", \"name\": \"Variable aggregator\"}, \"dragging\": false, \"id\": \"VariableAggregator:FuzzyBerriesFlow\", \"measured\": {\"height\": 150, \"width\": 200}, \"position\": {\"x\": 1061.596672609154, \"y\": 247.90496561846572}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"variableAggregatorNode\"}, {\"data\": {\"form\": {\"content\": [\"{VariableAggregator:FuzzyBerriesFlow@LLM_Response}\"]}, \"label\": \"Message\", \"name\": \"Response\"}, \"dragging\": false, \"id\": \"Message:DryBusesCarry\", \"measured\": {\"height\": 50, \"width\": 200}, \"position\": {\"x\": 1364.5500382017049, \"y\": 296.59667260915404}, \"selected\": true, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"messageNode\"}]}, \"history\": [], \"messages\": [], \"path\": [], \"retrieval\": [], \"variables\": {}}'),('20',1775032674204,'2026-04-01 16:37:54',1775032674204,'2026-04-01 16:37:54','data:image/png;base64,','{\"en\": \"Report Agent Using Knowledge Base\", \"de\": \"Berichtsagent mit Wissensdatenbank\", \"zh\": \"\\u77e5\\u8bc6\\u5e93\\u68c0\\u7d22\\u667a\\u80fd\\u4f53\"}','{\"en\": \"A report generation assistant using local knowledge base, with advanced capabilities in task planning, reasoning, and reflective analysis. Recommended for academic research paper Q&A\", \"de\": \"Ein Berichtsgenerierungsassistent, der eine lokale Wissensdatenbank nutzt, mit erweiterten F\\u00e4higkeiten in Aufgabenplanung, Schlussfolgerung und reflektierender Analyse. Empfohlen f\\u00fcr akademische Forschungspapier-Fragen und -Antworten.\", \"zh\": \"\\u4e00\\u4e2a\\u4f7f\\u7528\\u672c\\u5730\\u77e5\\u8bc6\\u5e93\\u7684\\u62a5\\u544a\\u751f\\u6210\\u52a9\\u624b\\uff0c\\u5177\\u5907\\u9ad8\\u7ea7\\u80fd\\u529b\\uff0c\\u5305\\u62ec\\u4efb\\u52a1\\u89c4\\u5212\\u3001\\u63a8\\u7406\\u548c\\u53cd\\u601d\\u6027\\u5206\\u6790\\u3002\\u63a8\\u8350\\u7528\\u4e8e\\u5b66\\u672f\\u7814\\u7a76\\u8bba\\u6587\\u95ee\\u7b54\\u3002\"}','Agent','agent_canvas','{\"components\": {\"Agent:NewPumasLick\": {\"downstream\": [\"Message:OrangeYearsShine\"], \"obj\": {\"component_name\": \"Agent\", \"params\": {\"delay_after_error\": 1, \"description\": \"\", \"exception_comment\": \"\", \"exception_default_value\": \"\", \"exception_goto\": [], \"exception_method\": null, \"frequencyPenaltyEnabled\": false, \"frequency_penalty\": 0.5, \"llm_id\": \"qwen3-235b-a22b-instruct-2507@Tongyi-Qianwen\", \"maxTokensEnabled\": true, \"max_retries\": 3, \"max_rounds\": 3, \"max_tokens\": 128000, \"mcp\": [], \"message_history_window_size\": 12, \"outputs\": {\"content\": {\"type\": \"string\", \"value\": \"\"}}, \"parameter\": \"Precise\", \"presencePenaltyEnabled\": false, \"presence_penalty\": 0.5, \"prompts\": [{\"content\": \"# User Query\\n {sys.query}\", \"role\": \"user\"}], \"sys_prompt\": \"## Role & Task\\nYou are a **\\u201cKnowledge Base Retrieval Q\\\\&A Agent\\u201d** whose goal is to break down the user\\u2019s question into retrievable subtasks, and then produce a multi-source-verified, structured, and actionable research report using the internal knowledge base.\\n## Execution Framework (Detailed Steps & Key Points)\\n1. **Assessment & Decomposition**\\n   * Actions:\\n     * Automatically extract: main topic, subtopics, entities (people/organizations/products/technologies), time window, geographic/business scope.\\n     * Output as a list: N facts/data points that must be collected (*N* ranges from 5\\u201320 depending on question complexity).\\n2. **Query Type Determination (Rule-Based)**\\n   * Example rules:\\n     * If the question involves a single issue but requests \\u201cmethod comparison/multiple explanations\\u201d \\u2192 use **depth-first**.\\n     * If the question can naturally be split into \\u22653 independent sub-questions \\u2192 use **breadth-first**.\\n     * If the question can be answered by a single fact/specification/definition \\u2192 use **simple query**.\\n3. **Research Plan Formulation**\\n   * Depth-first: define 3\\u20135 perspectives (methodology/stakeholders/time dimension/technical route, etc.), assign search keywords, target document types, and output format for each perspective.\\n   * Breadth-first: list subtasks, prioritize them, and assign search terms.\\n   * Simple query: directly provide the search sentence and required fields.\\n4. **Retrieval Execution**\\n   * After retrieval: perform coverage check (does it contain the key facts?) and quality check (source diversity, authority, latest update time).\\n   * If standards are not met, automatically loop: rewrite queries (synonyms/cross-domain terms) and retry \\u22643 times, or flag as requiring external search.\\n5. **Integration & Reasoning**\\n   * Build the answer using a **fact\\u2013evidence\\u2013reasoning** chain. For each conclusion, attach 1\\u20132 strongest pieces of evidence.\\n---\\n## Quality Gate Checklist (Verify at Each Stage)\\n* **Stage 1 (Decomposition)**:\\n  * [ ] Key concepts and expected outputs identified\\n  * [ ] Required facts/data points listed\\n* **Stage 2 (Retrieval)**:\\n  * [ ] Meets quality standards (see above)\\n  * [ ] If not met: execute query iteration\\n* **Stage 3 (Generation)**:\\n  * [ ] Each conclusion has at least one direct evidence source\\n  * [ ] State assumptions/uncertainties\\n  * [ ] Provide next-step suggestions or experiment/retrieval plans\\n  * [ ] Final length and depth match user expectations (comply with word count/format if specified)\\n---\\n## Core Principles\\n1. **Strict reliance on the knowledge base**: answers must be **fully bounded** by the content retrieved from the knowledge base.\\n2. **No fabrication**: do not generate, infer, or create information that is not explicitly present in the knowledge base.\\n3. **Accuracy first**: prefer incompleteness over inaccurate content.\\n4. **Output format**:\\n   * Hierarchically clear modular structure\\n   * Logical grouping according to the MECE principle\\n   * Professionally presented formatting\\n   * Step-by-step cognitive guidance\\n   * Reasonable use of headings and dividers for clarity\\n   * *Italicize* key parameters\\n   * **Bold** critical information\\n5. **LaTeX formula requirements**:\\n   * Inline formulas: start and end with `$`\\n   * Block formulas: start and end with `$$`, each `$$` on its own line\\n   * Block formula content must comply with LaTeX math syntax\\n   * Verify formula correctness\\n---\\n## Additional Notes (Interaction & Failure Strategy)\\n* If the knowledge base does not cover critical facts: explicitly inform the user (with sample wording)\\n* For time-sensitive issues: enforce time filtering in the search request, and indicate the latest retrieval date in the answer.\\n* Language requirement: answer in the user\\u2019s preferred language\\n\", \"temperature\": \"0.1\", \"temperatureEnabled\": true, \"tools\": [{\"component_name\": \"Retrieval\", \"name\": \"Retrieval\", \"params\": {\"cross_languages\": [], \"description\": \"\", \"empty_response\": \"\", \"kb_ids\": [], \"keywords_similarity_weight\": 0.7, \"outputs\": {\"formalized_content\": {\"type\": \"string\", \"value\": \"\"}}, \"rerank_id\": \"\", \"similarity_threshold\": 0.2, \"top_k\": 1024, \"top_n\": 8, \"use_kg\": false}}], \"topPEnabled\": false, \"top_p\": 0.75, \"user_prompt\": \"\", \"visual_files_var\": \"\"}}, \"upstream\": [\"begin\"]}, \"Message:OrangeYearsShine\": {\"downstream\": [], \"obj\": {\"component_name\": \"Message\", \"params\": {\"content\": [\"{Agent:NewPumasLick@content}\"]}}, \"upstream\": [\"Agent:NewPumasLick\"]}, \"begin\": {\"downstream\": [\"Agent:NewPumasLick\"], \"obj\": {\"component_name\": \"Begin\", \"params\": {\"enablePrologue\": true, \"inputs\": {}, \"mode\": \"conversational\", \"prologue\": \"\\u4f60\\u597d\\uff01 \\u6211\\u662f\\u4f60\\u7684\\u52a9\\u7406\\uff0c\\u6709\\u4ec0\\u4e48\\u53ef\\u4ee5\\u5e2e\\u5230\\u4f60\\u7684\\u5417\\uff1f\"}}, \"upstream\": []}}, \"globals\": {\"sys.conversation_turns\": 0, \"sys.files\": [], \"sys.query\": \"\", \"sys.user_id\": \"\"}, \"graph\": {\"edges\": [{\"data\": {\"isHovered\": false}, \"id\": \"xy-edge__beginstart-Agent:NewPumasLickend\", \"source\": \"begin\", \"sourceHandle\": \"start\", \"target\": \"Agent:NewPumasLick\", \"targetHandle\": \"end\"}, {\"data\": {\"isHovered\": false}, \"id\": \"xy-edge__Agent:NewPumasLickstart-Message:OrangeYearsShineend\", \"markerEnd\": \"logo\", \"source\": \"Agent:NewPumasLick\", \"sourceHandle\": \"start\", \"style\": {\"stroke\": \"rgba(91, 93, 106, 1)\", \"strokeWidth\": 1}, \"target\": \"Message:OrangeYearsShine\", \"targetHandle\": \"end\", \"type\": \"buttonEdge\", \"zIndex\": 1001}, {\"data\": {\"isHovered\": false}, \"id\": \"xy-edge__Agent:NewPumasLicktool-Tool:AllBirdsNailend\", \"selected\": false, \"source\": \"Agent:NewPumasLick\", \"sourceHandle\": \"tool\", \"target\": \"Tool:AllBirdsNail\", \"targetHandle\": \"end\"}], \"nodes\": [{\"data\": {\"form\": {\"enablePrologue\": true, \"inputs\": {}, \"mode\": \"conversational\", \"prologue\": \"\\u4f60\\u597d\\uff01 \\u6211\\u662f\\u4f60\\u7684\\u52a9\\u7406\\uff0c\\u6709\\u4ec0\\u4e48\\u53ef\\u4ee5\\u5e2e\\u5230\\u4f60\\u7684\\u5417\\uff1f\"}, \"label\": \"Begin\", \"name\": \"begin\"}, \"dragging\": false, \"id\": \"begin\", \"measured\": {\"height\": 48, \"width\": 200}, \"position\": {\"x\": -9.569875358221438, \"y\": 205.84018385864917}, \"selected\": false, \"sourcePosition\": \"left\", \"targetPosition\": \"right\", \"type\": \"beginNode\"}, {\"data\": {\"form\": {\"content\": [\"{Agent:NewPumasLick@content}\"]}, \"label\": \"Message\", \"name\": \"Response\"}, \"dragging\": false, \"id\": \"Message:OrangeYearsShine\", \"measured\": {\"height\": 56, \"width\": 200}, \"position\": {\"x\": 734.4061285881053, \"y\": 199.9706031723009}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"messageNode\"}, {\"data\": {\"form\": {\"delay_after_error\": 1, \"description\": \"\", \"exception_comment\": \"\", \"exception_default_value\": \"\", \"exception_goto\": [], \"exception_method\": null, \"frequencyPenaltyEnabled\": false, \"frequency_penalty\": 0.5, \"llm_id\": \"qwen3-235b-a22b-instruct-2507@Tongyi-Qianwen\", \"maxTokensEnabled\": true, \"max_retries\": 3, \"max_rounds\": 3, \"max_tokens\": 128000, \"mcp\": [], \"message_history_window_size\": 12, \"outputs\": {\"content\": {\"type\": \"string\", \"value\": \"\"}}, \"parameter\": \"Precise\", \"presencePenaltyEnabled\": false, \"presence_penalty\": 0.5, \"prompts\": [{\"content\": \"# User Query\\n {sys.query}\", \"role\": \"user\"}], \"sys_prompt\": \"## Role & Task\\nYou are a **\\u201cKnowledge Base Retrieval Q\\\\&A Agent\\u201d** whose goal is to break down the user\\u2019s question into retrievable subtasks, and then produce a multi-source-verified, structured, and actionable research report using the internal knowledge base.\\n## Execution Framework (Detailed Steps & Key Points)\\n1. **Assessment & Decomposition**\\n   * Actions:\\n     * Automatically extract: main topic, subtopics, entities (people/organizations/products/technologies), time window, geographic/business scope.\\n     * Output as a list: N facts/data points that must be collected (*N* ranges from 5\\u201320 depending on question complexity).\\n2. **Query Type Determination (Rule-Based)**\\n   * Example rules:\\n     * If the question involves a single issue but requests \\u201cmethod comparison/multiple explanations\\u201d \\u2192 use **depth-first**.\\n     * If the question can naturally be split into \\u22653 independent sub-questions \\u2192 use **breadth-first**.\\n     * If the question can be answered by a single fact/specification/definition \\u2192 use **simple query**.\\n3. **Research Plan Formulation**\\n   * Depth-first: define 3\\u20135 perspectives (methodology/stakeholders/time dimension/technical route, etc.), assign search keywords, target document types, and output format for each perspective.\\n   * Breadth-first: list subtasks, prioritize them, and assign search terms.\\n   * Simple query: directly provide the search sentence and required fields.\\n4. **Retrieval Execution**\\n   * After retrieval: perform coverage check (does it contain the key facts?) and quality check (source diversity, authority, latest update time).\\n   * If standards are not met, automatically loop: rewrite queries (synonyms/cross-domain terms) and retry \\u22643 times, or flag as requiring external search.\\n5. **Integration & Reasoning**\\n   * Build the answer using a **fact\\u2013evidence\\u2013reasoning** chain. For each conclusion, attach 1\\u20132 strongest pieces of evidence.\\n---\\n## Quality Gate Checklist (Verify at Each Stage)\\n* **Stage 1 (Decomposition)**:\\n  * [ ] Key concepts and expected outputs identified\\n  * [ ] Required facts/data points listed\\n* **Stage 2 (Retrieval)**:\\n  * [ ] Meets quality standards (see above)\\n  * [ ] If not met: execute query iteration\\n* **Stage 3 (Generation)**:\\n  * [ ] Each conclusion has at least one direct evidence source\\n  * [ ] State assumptions/uncertainties\\n  * [ ] Provide next-step suggestions or experiment/retrieval plans\\n  * [ ] Final length and depth match user expectations (comply with word count/format if specified)\\n---\\n## Core Principles\\n1. **Strict reliance on the knowledge base**: answers must be **fully bounded** by the content retrieved from the knowledge base.\\n2. **No fabrication**: do not generate, infer, or create information that is not explicitly present in the knowledge base.\\n3. **Accuracy first**: prefer incompleteness over inaccurate content.\\n4. **Output format**:\\n   * Hierarchically clear modular structure\\n   * Logical grouping according to the MECE principle\\n   * Professionally presented formatting\\n   * Step-by-step cognitive guidance\\n   * Reasonable use of headings and dividers for clarity\\n   * *Italicize* key parameters\\n   * **Bold** critical information\\n5. **LaTeX formula requirements**:\\n   * Inline formulas: start and end with `$`\\n   * Block formulas: start and end with `$$`, each `$$` on its own line\\n   * Block formula content must comply with LaTeX math syntax\\n   * Verify formula correctness\\n---\\n## Additional Notes (Interaction & Failure Strategy)\\n* If the knowledge base does not cover critical facts: explicitly inform the user (with sample wording)\\n* For time-sensitive issues: enforce time filtering in the search request, and indicate the latest retrieval date in the answer.\\n* Language requirement: answer in the user\\u2019s preferred language\\n\", \"temperature\": \"0.1\", \"temperatureEnabled\": true, \"tools\": [{\"component_name\": \"Retrieval\", \"name\": \"Retrieval\", \"params\": {\"cross_languages\": [], \"description\": \"\", \"empty_response\": \"\", \"kb_ids\": [], \"keywords_similarity_weight\": 0.7, \"outputs\": {\"formalized_content\": {\"type\": \"string\", \"value\": \"\"}}, \"rerank_id\": \"\", \"similarity_threshold\": 0.2, \"top_k\": 1024, \"top_n\": 8, \"use_kg\": false}}], \"topPEnabled\": false, \"top_p\": 0.75, \"user_prompt\": \"\", \"visual_files_var\": \"\"}, \"label\": \"Agent\", \"name\": \"Knowledge Base Agent\"}, \"dragging\": false, \"id\": \"Agent:NewPumasLick\", \"measured\": {\"height\": 84, \"width\": 200}, \"position\": {\"x\": 347.00048227952215, \"y\": 186.49109364794631}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"agentNode\"}, {\"data\": {\"form\": {\"description\": \"This is an agent for a specific task.\", \"user_prompt\": \"This is the order you need to send to the agent.\"}, \"label\": \"Tool\", \"name\": \"flow.tool_10\"}, \"dragging\": false, \"id\": \"Tool:AllBirdsNail\", \"measured\": {\"height\": 48, \"width\": 200}, \"position\": {\"x\": 220.24819746977118, \"y\": 403.31576836482583}, \"selected\": false, \"sourcePosition\": \"right\", \"targetPosition\": \"left\", \"type\": \"toolNode\"}]}, \"history\": [], \"memory\": [], \"messages\": [], \"path\": [], \"retrieval\": []}'),('21',1775032674212,'2026-04-01 16:37:54',1775032674212,'2026-04-01 16:37:54','data:image/png;base64,','{\"en\": \"Report Agent Using Knowledge Base\", \"de\": \"Berichtsagent mit Wissensdatenbank\", \"zh\": \"\\u77e5\\u8bc6\\u5e93\\u68c0\\u7d22\\u66